const input = $input.first().json;
let params = {};
try {
  params = typeof input.chatInput === 'string' 
    ? JSON.parse(input.chatInput) 
    : input.chatInput;
} catch (e) { params = {}; }

return [{
  json: {
    domain: params.domain || null,
    category: params.category || null
  }
}];
